import { useMemo, useState } from 'react';
import ConfirmModal from '../components/common/ConfirmModal';
import SOSButton from '../components/common/SOSButton';
import { triggerSOS } from '../api/sos.api';
import { useAuth } from '../context/AuthContext';
import { useToast } from '../components/common/ToastProvider';

function SOS() {
  const { user } = useAuth();
  const { pushToast } = useToast();
  const [location, setLocation] = useState('');
  const [status, setStatus] = useState('idle');
  const [openConfirm, setOpenConfirm] = useState(false);
  const [sending, setSending] = useState(false);

  const timeline = useMemo(() => {
    if (status === 'idle') return ['Waiting for SOS trigger'];
    if (status === 'sent') return ['SOS triggered', 'Dispatcher notified', 'Awaiting response'];
    return ['SOS triggered', 'Help dispatched', 'Assistance reached'];
  }, [status]);

  const detectLocation = () => {
    if (!navigator.geolocation) {
      pushToast('Geolocation is not supported in this browser.', 'warning');
      return;
    }

    navigator.geolocation.getCurrentPosition(
      (pos) => {
        setLocation(`${pos.coords.latitude.toFixed(5)}, ${pos.coords.longitude.toFixed(5)}`);
        pushToast('Location detected.', 'success');
      },
      () => pushToast('Unable to fetch location. Enter manually.', 'danger')
    );
  };

  const handleTrigger = async () => {
    try {
      setSending(true);
      await triggerSOS({
        userId: user?.id || 0,
        message: 'Emergency SOS triggered',
        location: location || 'Location not provided'
      });
      setStatus('sent');
      pushToast('SOS alert sent successfully.', 'success');
      setTimeout(() => setStatus('active'), 2500);
    } catch {
      pushToast('Could not send SOS. Please retry.', 'danger');
    } finally {
      setSending(false);
      setOpenConfirm(false);
    }
  };

  return (
    <div className='container py-5'>
      <div className='row justify-content-center'>
        <div className='col-12 col-lg-8'>
          <div className='card card-soft p-4 text-center'>
            <h2 className='mb-2'>Emergency SOS</h2>
            <p className='text-muted'>One-click emergency trigger with location sharing.</p>

            <div className='my-4'>
              <SOSButton onClick={() => setOpenConfirm(true)} disabled={sending} large />
            </div>

            <div className='row g-2 align-items-center'>
              <div className='col-md-8'>
                <input
                  className='form-control'
                  value={location}
                  onChange={(e) => setLocation(e.target.value)}
                  placeholder='Auto-detected or manual location'
                  aria-label='Emergency location'
                />
              </div>
              <div className='col-md-4 d-grid'>
                <button className='btn btn-outline-secondary' onClick={detectLocation}>Auto Detect</button>
              </div>
            </div>

            <div className='timeline-box mt-4 text-start'>
              <h6>Status Tracking</h6>
              <ul className='mb-0'>
                {timeline.map((item) => (
                  <li key={item}>{item}</li>
                ))}
              </ul>
            </div>
          </div>
        </div>
      </div>

      <ConfirmModal
        open={openConfirm}
        title='Confirm SOS Alert'
        body='Do you want to send the SOS alert now? This will notify available responders.'
        confirmText='Send SOS'
        onConfirm={handleTrigger}
        onCancel={() => setOpenConfirm(false)}
        loading={sending}
      />
    </div>
  );
}

export default SOS;
